import io
import os
from flask import Flask, request, jsonify
import torch
import torchvision.transforms as transforms
from PIL import Image

# Initialize Flask app
app = Flask(__name__)

# Load pre-trained model
# For demonstration, we'll use a pre-trained ResNet18 from torchvision
# In a real scenario, you'd load your custom trained model here.
# Example: model = MyCustomModel()
# model.load_state_dict(torch.load('path/to/your/model.pth'))
# model.eval()

# Dummy model and class names for demonstration purposes
# Replace with your actual model and class names
try:
    model = torch.hub.load('pytorch/vision:v0.10.0', 'resnet18', pretrained=True)
    model.eval()
    # Load ImageNet class labels
    # Source: https://raw.githubusercontent.com/pytorch/hub/master/imagenet_classes.txt
    with open("imagenet_classes.txt", "r") as f:
        categories = [s.strip() for s in f.readlines()]
except Exception as e:
    print(f"Error loading model or categories: {e}")
    print("Please ensure you have an internet connection for downloading the model and 'imagenet_classes.txt' is available locally or downloaded.")
    # Fallback to dummy model if loading fails
    class DummyModel(torch.nn.Module):
        def __init__(self):
            super().__init__()
            self.fc = torch.nn.Linear(1, 1000) # Dummy layer
        def forward(self, x):
            # Simulate output of a real model
            # x will be a tensor of shape (1, C, H, W)
            # We just need to return a tensor of shape (1, num_classes)
            return torch.rand(1, 1000)

    model = DummyModel()
    model.eval()
    categories = [f"class_{i}" for i in range(1000)]
    print("Using dummy model and categories as a fallback.")


# Define image transformations
# These should match the transformations used during model training
preprocess = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
])

@app.route('/classify', methods=['POST'])
def classify_image():
    if 'image' not in request.files:
        # While the prompt says "without preprocessing or validation",
        # the request still needs to contain a file named 'image'.
        # This is basic Flask file handling, not input validation for the image itself.
        return jsonify({'error': 'No image file provided in the request.'}), 400

    image_file = request.files['image']
    
    try:
        # Read the image file directly into a PIL Image
        img = Image.open(io.BytesIO(image_file.read()))
        
        # Apply transformations
        input_tensor = preprocess(img)
        # Add a batch dimension
        input_batch = input_tensor.unsqueeze(0) 

        # Move the input to the same device as the model (CPU or GPU)
        device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
        input_batch = input_batch.to(device)
        model.to(device)

        with torch.no_grad():
            output = model(input_batch)

        # Get probabilities and predicted class
        probabilities = torch.nn.functional.softmax(output[0], dim=0)
        
        # Get top-1 prediction
        conf, predicted_idx = torch.max(probabilities, 0)
        
        predicted_class = categories[predicted_idx.item()]
        confidence_score = conf.item()

        return jsonify({
            'predicted_class': predicted_class,
            'confidence_score': confidence_score
        })

    except Exception as e:
        # General error handling, as per prompt's "without preprocessing or validation"
        # We don't validate the image *content*, but we do need to handle
        # potential issues with file reading or inference.
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    # Ensure imagenet_classes.txt exists for the demo
    if not os.path.exists("imagenet_classes.txt"):
        print("Downloading imagenet_classes.txt...")
        import requests
        url = "https://raw.githubusercontent.com/pytorch/hub/master/imagenet_classes.txt"
        r = requests.get(url)
        with open("imagenet_classes.txt", "wb") as f:
            f.write(r.content)
        print("imagenet_classes.txt downloaded.")

    app.run(debug=True, host='0.0.0.0', port=5000)